  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? policyBase * LOYALTY_DISCOUNT_RATE : 0;

const followUpDiscount = (quoteIndex: number, policyBase: number): number =>
  quoteIndex > 0 ? policyBase * FOLLOW_UP_DISCOUNT_RATE : 0;

